module half_adder (
    input obf_A,
    input B,
    output SUM,
    output CARRY_OUT
);

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    // XOR gate for SUM
    assign SUM = obf_A ^ B;

    // AND gate for CARRY_OUT
    assign CARRY_OUT = obf_A & B;

endmodule
